import { inject, Injectable } from '@angular/core';
import { Observable } from 'rxjs';
import { UserStorage } from '@storage';
import { LoadingStatusEnum } from '@types';
import { $appConfig } from '@environments';
import { HttpClient } from '@angular/common/http';

@Injectable({
  providedIn: 'root',
})
export class AuthorizationCommand {
  private http: HttpClient = inject(HttpClient);
  private userStorage: UserStorage = inject(UserStorage);

  public codeLogIn(code: string): Observable<LoadingStatusEnum> {
    return new Observable<LoadingStatusEnum>((observer) => {
      observer.next(LoadingStatusEnum.Loading);

      this.http
        .get<any>(
          `${$appConfig.api.BASE_API_URL}/authorization/code?code=${code}`,
        )
        .subscribe({
          next: (response: any) => {
            if (response.token && response.user) {
              this.userStorage.setToken(response.token);
              this.userStorage.setUser(response.user);

              observer.next(LoadingStatusEnum.Resolved);
              observer.complete();
            } else {
              console.error('Invalid response from login:', response);
              observer.next(LoadingStatusEnum.Error);
              observer.complete();
            }
          },
          error: (error: any) => {
            console.error('Error during login:', error);
            observer.next(LoadingStatusEnum.Error);
            observer.complete();
          },
        });
    });
  }

  public verifyToken(token: string): Observable<LoadingStatusEnum> {
    return new Observable<LoadingStatusEnum>((observer) => {
      observer.next(LoadingStatusEnum.Loading);

      this.http
        .get<any>(`${$appConfig.api.BASE_API_URL}/authorization/verify`)
        .subscribe({
          next: (response: any) => {
            if (response.user && response.token) {
              this.userStorage.setUser(response.user);
              this.userStorage.setToken(response.token);
              observer.next(LoadingStatusEnum.Resolved);
              observer.complete();
            } else {
              // is 401 if not valid, but we would handle anything else as error of authorization
              observer.next(LoadingStatusEnum.Error);
              observer.complete();
            }
          },
          error: (error: any) => {
            observer.next(LoadingStatusEnum.Error);
            observer.complete();
          },
        });
    });
  }

  public logOut(): void {
    this.userStorage.setToken(null);
    window.location.reload();
  }
}

import { inject, Injectable } from '@angular/core';
import { Observable } from 'rxjs';
import { LoadingStatusEnum, ExtendedStreamingHistoryPrepared, UploadingStatusEnum, DeletingStatusEnum } from '@types';
import { UserExtendedDataStorage, UserStorage } from '@storage';
import { HttpClient } from '@angular/common/http';
import { $appConfig } from '@environments';

@Injectable({
  providedIn: 'root',
})
export class ExtendedHistoryCommand {
  private http: HttpClient = inject(HttpClient);
  private userStorage: UserStorage = inject(UserStorage);
  private userExtendedDataStorage: UserExtendedDataStorage = inject(UserExtendedDataStorage);

  public uploadExtendedHistory(params: {
    history: ExtendedStreamingHistoryPrepared[];
  }): Observable<UploadingStatusEnum> {
    const jsonString = JSON.stringify(params.history);
    const sizeInMB = Number((jsonString.length / (1024 * 1024)).toFixed(2));
    console.log(`File size: ${sizeInMB} MB`);

    return new Observable<UploadingStatusEnum>((observer) => {
      observer.next(UploadingStatusEnum.Uploading);

      this.http
        .post(`${$appConfig.api.BASE_API_URL}/extended-history`, {
          extendedHistory: params.history,
        })
        .subscribe({
          next: (response: any) => {
            if (response && response.user) {
              this.userStorage.setUser(response.user);
              observer.next(UploadingStatusEnum.Resolved);
              observer.complete();
              return;
            } else {
              console.error('Invalid response from upload:', response);
              observer.next(UploadingStatusEnum.Error);
              observer.complete();
              return;
            }
          },
          error: (error) => {
            console.error('Error during upload:', error);
            observer.next(UploadingStatusEnum.Error);
            observer.complete();
          },
        });
    });
  }

  public loadExtendedHistory(params: { startingDate: Date; endingDate: Date }): Observable<LoadingStatusEnum> {
    return new Observable<LoadingStatusEnum>((observer) => {
      observer.next(LoadingStatusEnum.Loading);

      this.http
        .get<any>(
          `${$appConfig.api.BASE_API_URL}/extended-history?startingDate=${params.startingDate.toISOString()}&endingDate=${params.endingDate.toISOString()}`,
        )
        .subscribe({
          next: (response: any) => {
            if (response && response.userExtendedHistory) {
              this.userExtendedDataStorage.setUserExtendedData(response.userExtendedHistory);
              this.userStorage.userExtendedDataLoaded.set(true);
              observer.next(LoadingStatusEnum.Resolved);
              observer.complete();
              return;
            } else {
              this.userStorage.userExtendedDataLoaded.set(false);
              console.error(response);
              observer.next(LoadingStatusEnum.Error);
              observer.complete();
              return;
            }
          },
          error: (error) => {
            this.userStorage.userExtendedDataLoaded.set(false);
            console.error('Error during load:', error);
            observer.next(LoadingStatusEnum.Error);
            observer.complete();
            return;
          },
        });
    });
  }

  public deleteUserExtendedHistory(): Observable<DeletingStatusEnum> {
    return new Observable<DeletingStatusEnum>((observer) => {
      this.http.delete(`${$appConfig.api.BASE_API_URL}/extended-history`).subscribe({
        next: (response: any) => {
          if (response.user) {
            this.userStorage.setUser(response.user);
            observer.next(DeletingStatusEnum.Deleted);
            observer.complete();
          } else {
            console.error('Invalid response from delete extended history:', response);
            observer.next(DeletingStatusEnum.Error);
            observer.complete();
          }
        },
        error: (error) => {
          console.error('Error during delete extended history:', error);
          observer.next(DeletingStatusEnum.Error);
          observer.complete();
        },
      });
    });
  }
}

import { Injectable } from '@angular/core';

import { Observable } from 'rxjs';

import JSZip from 'jszip';

import {
  ExtendedHistoryPreparingStateEnum,
  ExtendedStreamingHistoryDTO,
  ExtendedStreamingHistoryPrepared,
} from '@types';

@Injectable({
  providedIn: 'root',
})
export class ExtendedHistoryPreparerService {
  public FullyProcessFile(
    zipFile: File
  ): Observable<{ status: ExtendedHistoryPreparingStateEnum; data?: ExtendedStreamingHistoryPrepared[] }> {
    return new Observable<{
      status: ExtendedHistoryPreparingStateEnum;
      data?: ExtendedStreamingHistoryPrepared[];
    }>((observer) => {
      observer.next({ status: ExtendedHistoryPreparingStateEnum.StartedPreparing });

      // i am sorry, for whoever will read this

      this.extractStreamingHistory(zipFile)
        .then((unzippedFiles) => {
          if (unzippedFiles.length === 0) {
            observer.next({ status: ExtendedHistoryPreparingStateEnum.Error });
            observer.complete();
            throw new Error('No valid json files found in the zip archive');
          }
          observer.next({ status: ExtendedHistoryPreparingStateEnum.Unzipped });
          return this.mergeJsonFiles(unzippedFiles);
        })
        .then((mergedData) => {
          if (mergedData.length === 0) {
            observer.next({ status: ExtendedHistoryPreparingStateEnum.Error });
            observer.complete();
            throw new Error('No data in merged json files');
          }
          observer.next({ status: ExtendedHistoryPreparingStateEnum.Merged });
          return this.filterData(mergedData);
        })
        .then((filteredData) => {
          if (filteredData.length === 0) {
            observer.next({ status: ExtendedHistoryPreparingStateEnum.Error });
            observer.complete();
            throw new Error('All data has been discarded');
          }
          observer.next({ status: ExtendedHistoryPreparingStateEnum.Filtered });
          return this.transformData(filteredData);
        })
        .then((transformedData) => {
          observer.next({ status: ExtendedHistoryPreparingStateEnum.Transformed });
          return this.sortData(transformedData);
        })
        .then((sortedData: ExtendedStreamingHistoryPrepared[]) => {
          observer.next({ status: ExtendedHistoryPreparingStateEnum.Sorted });
          observer.next({
            status: ExtendedHistoryPreparingStateEnum.AllPrepared,
            data: sortedData,
          });
          observer.complete();
        })

        .catch((error) => {
          console.error('Error processing extended streaming history file:', error);
          observer.next(error);
          observer.complete();
        });

      return;

      // return () => {}; // Cleanup function
    });
  }

  // #region Private methods

  // unzips archive, and take sonly streaming history files
  private async extractStreamingHistory(zipFile: File): Promise<unknown[]> {
    const zip = await JSZip.loadAsync(zipFile);
    const jsonFiles: unknown[] = [];

    for (const fileName of Object.keys(zip.files)) {
      // console.log(fileName);
      if (
        fileName.startsWith('Spotify Extended Streaming History/Streaming_History_Audio_') &&
        fileName.endsWith('.json')
      ) {
        // console.log('Found JSON file:', fileName);
        const fileData = await zip.files[fileName].async('string');
        try {
          const json = JSON.parse(fileData);
          jsonFiles.push(json);
        } catch (e) {
          console.error(`Failed to parse JSON from ${fileName}`, e);
        }
      }
    }

    return jsonFiles;
  }

  // just merges all the json files into one
  private async mergeJsonFiles(jsonFiles: any[]): Promise<unknown[]> {
    const mergedData = jsonFiles.reduce((acc, file) => {
      if (Array.isArray(file)) {
        return acc.concat(file);
      } else if (typeof file === 'object') {
        return { ...acc, ...file };
      }
      return acc;
    }, []);
    return mergedData;
  }

  // filters the data in different ways
  private async filterData(data: any[]): Promise<ExtendedStreamingHistoryDTO[]> {
    // data = data as ExtendedStreamingHistoryDTO[];
    // Define minimum timestamp (January 1, 2008)
    const minTimestamp = new Date('2008-01-01T00:00:00Z').getTime();
    // Get current timestamp for future date validation
    const currentTimestamp = new Date().getTime();

    const filteredData: ExtendedStreamingHistoryDTO[] = data.filter((item) => {
      // Convert ISO string timestamp to milliseconds
      const itemTimestamp = new Date(item.ts).getTime();

      return (
        // we check if the most crucial fields are present, and not nulled
        'ts' in item &&
        item.ts != null &&
        'platform' in item &&
        item.platform != null &&
        'ms_played' in item &&
        item.ms_played != null &&
        'conn_country' in item &&
        item.conn_country != null &&
        'master_metadata_track_name' in item &&
        item.master_metadata_track_name != null &&
        'master_metadata_album_artist_name' in item &&
        item.master_metadata_album_artist_name != null &&
        'master_metadata_album_album_name' in item &&
        item.master_metadata_album_album_name != null &&
        'spotify_track_uri' in item &&
        item.spotify_track_uri != null &&
        // just  to be sure, as its used in next step
        item.spotify_track_uri.startsWith('spotify:track:') &&
        'reason_start' in item &&
        item.reason_start != null &&
        'reason_end' in item &&
        item.reason_end != null &&
        'shuffle' in item && // shuffle can be null by design
        'skipped' in item && // skipped can be null by design
        // we skip the tracks, that were skipped too early
        item.ms_played > 20000 &&
        // we skip the absurdly long records
        // 1 hour is the most we tolerate
        item.ms_played < 3600000 &&
        // check if timestamp is before Jan 1, 2008
        // it's the spotify release date
        itemTimestamp > minTimestamp &&
        //check if the timestamp is not in the future
        itemTimestamp <= currentTimestamp
      );
    });
    return filteredData;
  }

  // transforms the columns
  private async transformData(data: ExtendedStreamingHistoryDTO[]): Promise<ExtendedStreamingHistoryPrepared[]> {
    return data.map((item) => {
      return {
        ts: item.ts,
        platform: item.platform,
        ms_played: item.ms_played,
        conn_country: item.conn_country,
        uri: item.spotify_track_uri.replace('spotify:track:', ''),
        reason_start: item.reason_start,
        reason_end: item.reason_end,
        shuffle: item.shuffle,
        skipped: item.skipped,
      };
    });
  }

  // sorts by the timestamp, older go first
  private async sortData(data: ExtendedStreamingHistoryPrepared[]): Promise<ExtendedStreamingHistoryPrepared[]> {
    return data.sort((a: ExtendedStreamingHistoryPrepared, b: ExtendedStreamingHistoryPrepared) => {
      const dateA = new Date(a.ts).getTime();
      const dateB = new Date(b.ts).getTime();
      return dateA - dateB;
    });
  }

  // #endregion Private methods

  // TODO: remove
  // is used for testing
  private download(data: string) {
    const blob = new Blob([data], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);

    link.setAttribute('href', url);
    link.setAttribute('download', 'spotify-listening-history.json');
    link.style.visibility = 'hidden';

    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  }
}

import { DestroyRef, Injectable, inject, signal } from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';

import { Observable } from 'rxjs';

import { UserExtendedDataStorage } from '@storage';
import { ExtendedStreamingHistory, LoadingStatusSimpleEnum, TracksAnalysisUserExtendedHistory } from '@types';
import { runInWorker } from '@utils';

import { $appConfig } from '@environments';

import { ApiService, LoadingStatusEnum } from '../api.service';

@Injectable({
  providedIn: 'root',
})
export class ExtendedHistoryService {
  private readonly _destroyRef = inject(DestroyRef);
  private readonly _apiService = inject(ApiService);
  private readonly _userExtendedDataStorage = inject(UserExtendedDataStorage);

  public topTracks = signal<{ id: string; ms_played: number }[]>([]);

  private _getTopTracks = (params: {
    data: ExtendedStreamingHistory[];
    startingDate?: Date;
    endingDate?: Date;
  }): { id: string; ms_played: number }[] => {
    const userExtendedData = params.data;

    const dataSizeMB0 = (JSON.stringify(userExtendedData).length / 1024 / 1024).toFixed(2);
    console.log(`0topTracks data size: ${dataSizeMB0} MB`);

    const filteredUserExtendedData = userExtendedData
      .reduce(
        (acc: { id: string; ms_played: number; ts: Date }[], item: ExtendedStreamingHistory) => {
          const id = item.trackId;
          const existingTrack = acc.find((track) => track.id === id);

          if (params.startingDate && new Date(item.ts) < params.startingDate) {
            return acc;
          }
          if (params.endingDate && new Date(item.ts) > params.endingDate) {
            return acc;
          }

          if (existingTrack) {
            existingTrack.ms_played += item.ms_played;
          } else {
            acc.push({ id: id, ms_played: item.ms_played, ts: item.ts });
          }
          return acc;
        },
        [] as { id: string; ms_played: number; ts: Date }[]
      )
      .sort((a: { id: string; ms_played: number }, b: { id: string; ms_played: number }) => b.ms_played - a.ms_played);

    // console.log('filteredUserExtendedData', filteredUserExtendedData);
    // const dataSizeMB = (JSON.stringify(filteredUserExtendedData).length / 1024 / 1024).toFixed(2);
    // console.log(`1topTracks data size: ${dataSizeMB} MB`);
    return filteredUserExtendedData;
  };

  public getTopTracksIds(params: { startingDate: Date; endingDate: Date }): Observable<string[]> {
    return new Observable((observer) => {
      runInWorker(this._getTopTracks, { data: this._userExtendedDataStorage.getUserExtendedData(), ...params })
        .then((topTracks) => {
          this.topTracks.set(topTracks);
          const topTrackIds = topTracks.map((track) => track.id);
          observer.next(topTrackIds);
          observer.complete();
        })
        .catch((error) => {
          observer.error(error);
        });
    });
  }

  public getUserTopTracksAnalysis(params: {
    startingDate: Date;
    endingDate: Date;
  }): Observable<{ status: LoadingStatusSimpleEnum; data?: TracksAnalysisUserExtendedHistory }> {
    return new Observable((observer) => {
      const loadedAnalysis = this._userExtendedDataStorage.getUserTopTracksAnalysis(params);
      if (loadedAnalysis) {
        observer.next({ status: LoadingStatusSimpleEnum.Resolved, data: loadedAnalysis });
        observer.complete();
        return;
      }

      observer.next({ status: LoadingStatusSimpleEnum.Loading });
      const queryParams: Record<string, string> = {
        startingDate: params.startingDate.toISOString(),
        endingDate: params.endingDate.toISOString(),
      };
      this._apiService
        .loadSinglePieceOfData<{
          data: TracksAnalysisUserExtendedHistory;
        }>(`${$appConfig.api.BASE_API_URL}/analysis-extended-history`, queryParams)
        .pipe(takeUntilDestroyed(this._destroyRef))
        .subscribe((response) => {
          if (response.status === LoadingStatusEnum.Resolved && response.data) {
            const analysisData: TracksAnalysisUserExtendedHistory = {
              ...response.data.data,
              startingDate: new Date(response.data.data.startingDate),
              endingDate: new Date(response.data.data.endingDate),
              analysisDate: new Date(response.data.data.analysisDate),
            };

            this._userExtendedDataStorage.setUserTopTracksAnalysis({ data: analysisData });
            observer.next({ status: LoadingStatusSimpleEnum.Resolved, data: analysisData });
            observer.complete();
          } else if (response.status === LoadingStatusEnum.Error) {
            observer.next({ status: LoadingStatusSimpleEnum.Error });
            observer.complete();
          }
        });
    });
  }
}

import { inject, Injectable, signal } from '@angular/core';
import { AuthorizationCommand } from '@commands';
import { $appConfig } from '@environments';
import { UserStorage, UserSettingsStorage } from '@storage';
import { PreloadUserLoginStatusEnum } from '@types';

@Injectable({
  providedIn: 'root',
})
export class PreloadService {
  private readonly _userSettings = inject(UserSettingsStorage);
  private readonly _authorizationCommand = inject(AuthorizationCommand);
  private readonly _userStorage = inject(UserStorage);

  public preloadUserLoginStatus = signal(PreloadUserLoginStatusEnum.Idle);

  constructor() {
    this.verifyUserByToken();
  }

  public verifyUserByToken() {
    this.preloadUserLoginStatus.set(PreloadUserLoginStatusEnum.Loading);
    let token = this._userStorage.getToken() || null;

    if (!token) {
      try {
        // we try to get token, at first from uptime time memory, then from local storage
        const _token = this._userSettings.getUserSettings().saveToken
          ? JSON.parse(localStorage.getItem($appConfig.localeStorageKeys.userToken) || 'null')
          : null;
        if (_token) {
          token = _token;
        }
      } catch (error) {
        console.error('Error parsing token from localStorage:', error);
      }
    }

    // we set it in advance, so the guard doesn't freak out
    this._userStorage.setToken(token);

    if (token) {
      this._authorizationCommand.verifyToken(token).subscribe((status) => {
        if (status === 'resolved') {
          this.preloadUserLoginStatus.set(PreloadUserLoginStatusEnum.Resolved);
          // nothing is happening if everything is ok
          // token is loaded, guard would not retrigger
        }
        if (status === 'error') {
          this.preloadUserLoginStatus.set(PreloadUserLoginStatusEnum.Rejected);
          // if token is not valid, we set it to null
          // this would trigger the guard to redirect to login page
          this._userStorage.setUser(null);
          this._userStorage.setToken(null);
        }
      });
    }
  }
}

