import { Injectable, signal, WritableSignal } from '@angular/core';
import { Album, Artist, Track } from '@types';

@Injectable({
  providedIn: 'root',
})
export class SpotifyItemsStorage {
  private readonly tracks: WritableSignal<Track[]> = signal([]);

  public getTrack(id: Track['id']): Track | null {
    return this.tracks().find((track) => track.id === id) || null;
  }
  public getTracks(ids: Track['id'][]): Track[] {
    return this.tracks().filter((track) => ids.includes(track.id));
  }
  public appendTracks(newTracks: Track[]): void {
    const currentTracks = this.tracks();
    const existingTrackIds = new Set(currentTracks.map((track) => track.id));
    const newTracksFiltered = newTracks.filter(
      (track) => !existingTrackIds.has(track.id)
    );
    this.tracks.set([...currentTracks, ...newTracksFiltered]);
  }

  private readonly artists: WritableSignal<Artist[]> = signal([]);

  public getArtist(id: Artist['id']): Artist | null {
    return this.artists().find((artist) => artist.id === id) || null;
  }
  public appendArtists(newArtists: Artist[]): void {
    const currentArtists = this.artists();
    const updatedArtists = [...currentArtists, ...newArtists];
    this.artists.set(updatedArtists);
  }

  private readonly albums: WritableSignal<Album[]> = signal([]);

  public getAlbum(id: Album['id']): Album | null {
    return this.albums().find((album) => album.id === id) || null;
  }
  public appendAlbums(newAlbums: Album[]): void {
    const currentAlbums = this.albums();
    const updatedAlbums = [...currentAlbums, ...newAlbums];
    this.albums.set(updatedAlbums);
  }
}

import { Injectable, signal, WritableSignal, DestroyRef, inject, OnDestroy } from '@angular/core';
import { ToastNotification } from '../types/shared';

@Injectable({
  providedIn: 'root',
})
export class ToastNotificationsService implements OnDestroy {
  private destroyRef = inject(DestroyRef);
  private toastNotifications: WritableSignal<ToastNotification[]> = signal([]);
  private timeouts = new Map<string, number>();

  ngOnDestroy(): void {
    this.destroyRef.onDestroy(() => {
      this.clearAllTimeouts();
    });
  }

  public getNotifications(): ToastNotification[] {
    return this.toastNotifications();
  }

  public sendNotification(notification: Omit<ToastNotification, 'id' | 'duration'> & { duration?: number }): void {
    const newNotification: ToastNotification = {
      ...notification,
      id: this.generateId(),
      duration: notification.duration || 5000,
    };

    this.toastNotifications.set([...this.toastNotifications(), newNotification]);

    // Auto-remove notification after duration
    if (newNotification.duration > 0) {
      this.scheduleRemoval(newNotification.id, newNotification.duration);
    }
  }

  public removeNotification(id: string): void {
    this.clearTimeout(id);
    this.toastNotifications.set(this.toastNotifications().filter((notification) => notification.id !== id));
  }

  public removeAllNotifications(): void {
    this.clearAllTimeouts();
    this.toastNotifications.set([]);
  }

  private scheduleRemoval(id: string, duration: number): void {
    const timeoutId = window.setTimeout(() => {
      this.removeNotification(id);
    }, duration);

    this.timeouts.set(id, timeoutId);
  }

  private clearTimeout(id: string): void {
    const timeoutId = this.timeouts.get(id);
    if (timeoutId) {
      window.clearTimeout(timeoutId);
      this.timeouts.delete(id);
    }
  }

  private clearAllTimeouts(): void {
    this.timeouts.forEach((timeoutId) => window.clearTimeout(timeoutId));
    this.timeouts.clear();
  }

  private generateId(): string {
    return Math.random().toString(36).substr(2, 9);
  }
}

import { inject, Injectable, Signal, signal, WritableSignal } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { BehaviorSubject } from 'rxjs';
import { catchError } from 'rxjs/operators';
import { SupportedLocaleEnum, TranslationFile } from '@types';
import { $appConfig } from '@environments';

// This service was entirely vibecoded ^^
// fuck you illya in future

@Injectable({
  providedIn: 'root',
})
export class TranslationService {
  private readonly _http = inject(HttpClient);

  private readonly currentLocale: WritableSignal<SupportedLocaleEnum> = signal($appConfig.defaultUserSettings.locale);
  private readonly translations: WritableSignal<Record<string, string>> = signal({});
  private readonly isLoading: WritableSignal<boolean> = signal(false);
  private initialized = false;

  // Observable for components that need to react to language changes
  private localeChange$ = new BehaviorSubject<SupportedLocaleEnum>(this.currentLocale());

  public readonly supportedLocales: SupportedLocaleEnum[] = $appConfig.localization.supportedLocales;

  getCurrentLocale(): Signal<SupportedLocaleEnum> {
    return this.currentLocale;
  }

  getTranslations(): Record<string, string> {
    return this.translations();
  }

  /**
   * Get loading state
   */
  getIsLoading(): boolean {
    return this.isLoading();
  }

  /**
   * Check if the translation service has been initialized
   */
  isInitialized(): boolean {
    return this.initialized;
  }

  /**
   * Translate a key to current language
   */
  translate(key: string, fallback?: string): string {
    const translation = this.translations()[key];
    if (translation) {
      return translation;
    }

    // If no translation is found and we have a fallback, use it
    if (fallback) {
      return fallback;
    }

    // If no translations are loaded yet, return a more user-friendly fallback
    const translations = this.translations();
    if (Object.keys(translations).length === 0 && !this.isLoading()) {
      // Return key without prefix for better UX during initialization
      return this.formatKeyAsFallback(key);
    }

    return key;
  }

  /**
   * Format a translation key as a user-friendly fallback
   */
  private formatKeyAsFallback(key: string): string {
    // Convert camelCase or snake_case to readable text
    return key
      .replace(/([A-Z])/g, ' $1') // Add space before capital letters
      .replace(/_/g, ' ') // Replace underscores with spaces
      .toLowerCase()
      .trim()
      .replace(/^./, (str) => str.toUpperCase()); // Capitalize first letter
  }

  /**
   * Set the current locale and load its translations
   */
  async setLocale(locale: SupportedLocaleEnum): Promise<void> {
    if (locale === this.currentLocale() && this.initialized) {
      return;
    }

    this.isLoading.set(true);

    try {
      await this.loadTranslations(locale);
      this.currentLocale.set(locale);
      this.localeChange$.next(locale);
      this.saveToStorage(locale);
      this.initialized = true;
    } catch (error) {
      console.error('Failed to load translations for locale:', locale, error);

      // If this is not the first initialization attempt and we're not trying English, fallback to English
      if (this.initialized || locale === 'en-US') {
        throw error;
      }

      console.warn('Falling back to English translations');
      try {
        await this.loadTranslations(SupportedLocaleEnum.EnglishUS);
        this.currentLocale.set(SupportedLocaleEnum.EnglishUS);
        this.localeChange$.next(SupportedLocaleEnum.EnglishUS);
        this.saveToStorage(SupportedLocaleEnum.EnglishUS);
        this.initialized = true;
      } catch (fallbackError) {
        console.error('Failed to load English fallback translations:', fallbackError);
        this.initialized = true; // Mark as initialized even if failed to prevent infinite loops
        throw fallbackError;
      }
    } finally {
      this.isLoading.set(false);
    }
  }

  /**
   * Load translations for a specific locale
   */
  private async loadTranslations(locale: SupportedLocaleEnum): Promise<void> {
    const translationFile = await this.getTranslationFile(locale);
    this.translations.set(translationFile.translations);
  }

  /**
   * Get translation file for a locale
   */
  private getTranslationFile(locale: SupportedLocaleEnum): Promise<TranslationFile> {
    const filePath = this.getTranslationFilePath(locale);

    return this._http
      .get<TranslationFile>(filePath)
      .pipe(
        catchError((error) => {
          console.error(`Failed to load translation file for ${locale}:`, error);
          // Fallback to English if the translation file fails to load
          if (locale !== 'en-US') {
            return this._http.get<TranslationFile>(this.getTranslationFilePath(SupportedLocaleEnum.EnglishUS));
          }
          throw error;
        }),
      )
      .toPromise() as Promise<TranslationFile>;
  }

  /**
   * Get the file path for a locale's translations
   */
  private getTranslationFilePath(locale: SupportedLocaleEnum): string {
    if (locale) {
      if (locale === SupportedLocaleEnum.EnglishUS) {
        return 'translations/source.json';
      } else {
        return `translations/locale.${locale}.json`;
      }
    } else {
      return 'translations/source.json';
    }
  }

  private saveToStorage(locale: SupportedLocaleEnum): void {
    localStorage.setItem($appConfig.localeStorageKeys.languageLocal, locale);
  }

  public getLocaleDisplayName(locale: SupportedLocaleEnum): string {
    switch (locale) {
      case 'en-US':
        return 'English';
      case 'uk':
        return 'Українська';
      case 'ja':
        return '日本語';
      default:
        return locale;
    }
  }
}

import { inject, Injectable } from '@angular/core';
import { UserStorage } from '@storage';
import { LoadingStatusEnum, Track } from '@types';
import { HttpClient } from '@angular/common/http';
import { $appConfig } from '@environments';
import { ToastNotificationsService } from '@libs';
import { Observable } from 'rxjs';

@Injectable({
  providedIn: 'root',
})
export class UserCommand {
  private _http: HttpClient = inject(HttpClient);

  private _toastNotificationsService: ToastNotificationsService = inject(ToastNotificationsService);
  private _userStorage: UserStorage = inject(UserStorage);

  public loadUser(): Observable<LoadingStatusEnum> {
    return new Observable<LoadingStatusEnum>((observer) => {
      observer.next(LoadingStatusEnum.Loading);

      this._http.get(`${$appConfig.api.BASE_API_URL}/user-private`).subscribe({
        next: (response: any) => {
          if (response.user) {
            this._userStorage.setUser(response.user);
            this._userStorage.userLoadingState.set(LoadingStatusEnum.Resolved);
          } else {
            console.error('Invalid response from user load:', response);
            this._userStorage.userLoadingState.set(LoadingStatusEnum.Error);
          }
        },
        error: (error: any) => {
          console.error('Error during user load:', error);
          this._toastNotificationsService.sendNotification({
            type: 'error',
            title: 'Error loading user data',
            message: error?.error || 'Unknown error',
          });
          observer.next(LoadingStatusEnum.Error);
          observer.complete();
        },
      });
    });
  }
}

