import { Component, inject, OnInit } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { $appConfig } from '@environments';
import { AuthorizationCommand } from '@commands';
import { LoadingStatusEnum } from '@types';
import { TranslatePipe } from '@pipes';
import { LoadingSpinner } from '@features';
import { ToastNotificationsService } from '@libs';

@Component({
  selector: 'app-login',
  imports: [TranslatePipe, LoadingSpinner],
  templateUrl: './login.component.html',
  styleUrl: './login.component.scss',
})
export default class LoginComponent implements OnInit {
  private router: Router = inject(Router);
  private activatedRoute: ActivatedRoute = inject(ActivatedRoute);

  private authorizationCommand: AuthorizationCommand = inject(AuthorizationCommand);
  private toastNotificationsService: ToastNotificationsService = inject(ToastNotificationsService);

  loadingState = LoadingStatusEnum.Idle;

  getAuthorizationUrl(): string {
    const state = '37';
    const scopes = $appConfig.spotify.authorization.scopes.join('%20');
    return `https://accounts.spotify.com/authorize?client_id=${$appConfig.spotify.clientId}&redirect_uri=${$appConfig.spotify.redirectUri}&response_type=code&state=${state}&scope=${scopes}&show_dialog=${$appConfig.spotify.authorization.showDialog}`;
  }

  ngOnInit() {
    this.activatedRoute.queryParams.subscribe((params) => {
      const code = params['code'];
      const state = params['state'];
      const error = params['error'];

      if (code && state) {
        this.authorizationCommand.codeLogIn(code).subscribe((loadingState) => {
          this.loadingState = loadingState;
          if (loadingState === LoadingStatusEnum.Resolved) {
            this.router.navigate(['/']);
          } else if (loadingState === LoadingStatusEnum.Error) {
            this.router.navigate([], {
              relativeTo: this.activatedRoute,
              queryParams: {},
              replaceUrl: true,
            });
          }
        });
      } else if (error) {
        this.toastNotificationsService.sendNotification({
          type: 'error',
          title: 'Error',
          message: `Error during authorization: ${error}`,
          duration: 5000,
        });
        this.router.navigate([], {
          relativeTo: this.activatedRoute,
          queryParams: {},
          replaceUrl: true,
        });
        console.error('Error during authorization:', error);
      }
    });
  }
}

